var e=JSON.parse(`[{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"출국비자를 마지막으로 이런 종이쪼가린 오래간만이군.","JPN":"こんな紙切れに何かを書くのは久しぶりだな。出国ビザ以来だ。","ENG":"This is the first document I've seen since my last exit visa.","TWN":"出國簽證最後變成這張紙。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"어이.","JPN":"おい。","ENG":"Yo.","TWN":"喂！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"두목은 스캐빈저의 주인이 누구라고 생각하지?","JPN":"ボスはスカベンジャーの主は誰だと思っている？","ENG":"Boss, who do you think owns us Scavengers?","TWN":"老大認為誰是清道夫的主人呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"물론 우릴 이끄는 우두머리가 있긴 하지만, 그건 스캐빈저의 시스템이 정한 우두머리일 뿐이야.","JPN":"もちろん俺たちを率いる頭はいるが、それはスカベンジャーのシステムが定めた頭に過ぎない。","ENG":"I'm not talking about the leader. She's just appointed by the Scavengers' system.","TWN":"雖然是有領導我們的長官，但他其實也只是訂定清道夫的系統而已。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>제일 강한 놈이 다 갖는다.</color>","JPN":"<color=#ffd34c>一番強い者がすべてを手に入れる。</color>","ENG":"<color=#ffd34c>Winner takes all.</color>","TWN":"<color=#ffd34c>最強的人全拿。</color>"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"그 규칙을 받아들이고 존재하게끔 하는 우리들이 스캐빈저의 주인이라 할 수 있지.","JPN":"そのルールを受け入れて存続させている我々が、スカベンジャーの主と言える。","ENG":"We made this rule to keep the Scavengers going. So we own ourselves.","TWN":"認同這個規則的我們，就可以說是清道夫的主人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"스캐빈저의 대다수는 이곳에 끌려와 노예로 일하던 녀석들이야.","JPN":"スカベンジャーのほとんどはさらわれてきて奴隷として働いていたやつらだ。","ENG":"Most of us Scavengers were dragged here as slaves.","TWN":"大部分的清道夫都是被拖來這裡當奴隸的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"시달리고, 싸우고, 적응해서 살아남은 자들이 밑바닥에서 여기까지 기어올라온 거지.","JPN":"苦しみ、戦い、適応して生き残った者たちがどん底からここまで這い上がってきた。","ENG":"We toiled, fought, and acclimated to survive at first, and then crawled all the way up here.","TWN":"經過折磨、鬥爭後，適應生存下來的人，都是是從谷底爬上來的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"여기선 나약해지면 죽고, 싸움을 피하려고 해도 죽어.","JPN":"ここは軟弱な者は死に、戦いを避けようしても死ぬ世界だ。","ENG":"Here, you'll die if you're weak. You'll also die if you avoid fighting.","TWN":"在這裡適者生存，不適者淘汰，無論是太弱或是避戰，都是死路一條。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"그럼에도 살아남기만 하면 많은 것들을 얻을 수 있기 때문에 떠나지 못해.","JPN":"それでも、生き残りさえすれば多くの物を得ることができるから去ることができない。","ENG":"But if you survive, you can get a lot of things. That's why we can't leave.","TWN":"即使如此，只要你能夠活下來，就可以獲得很多東西，所以也離不開。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"그건, 사람이 책임에 얽매이지 않을 때가 가장 행복하다는 사실을 깨달았기 때문이지.","JPN":"それは、人は責任に囚われない時が最も幸せである事実に気付いたからだ。","ENG":"It's also because we know we don't have to take any responsibility for our actions here.","TWN":"因為我發現，人不受責任約束的時候是最幸福的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"그래, 이런 종이 한 장에 발이 묶여서 쩔쩔매는 인생 같은 건 아주 불쾌한 거라고.","JPN":"そう。こんな紙一枚に縛られる人生なんて、とても不快なものなのさ。","ENG":"So, yes, a life bound by a piece of paper like this offends our very existence.","TWN":"沒錯，我認為因為一紙契約而綁手綁腳的人生是很不快樂的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"그러니 두목은 지금 스캐빈저에게 해선 안 될 제안을 한 거야.","JPN":"だからボスは今、スカベンジャーにしてはいけない提案をしたわけさ。","ENG":"In other words, Boss, you've made an impossible proposition to a Scavenger.","TWN":"所以老大您這個提議，對海盜而言是非常不恰當的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"……","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"으하하!! 알아들었으면 그걸로 됐어.","JPN":"ガハハハッ！！　わかったならそれでいい。","ENG":"Mwa hah hah! So long as you know.","TWN":"哇哈哈！！有聽懂的話，那就這麼決定囉！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"날 계속 부려먹고 싶댔나?","JPN":"俺をこの先ずっとこき使いたいと言ったな？","ENG":"You want to keep me in your service, huh?","TWN":"您想繼續使喚我？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"좋아. 이번엔 두목 뜻대로 하자고.","JPN":"いいぜ。今回はボスの意思に従う。","ENG":"Alright, I'll do as you want this time, Boss.","TWN":"好吧，這次就聽老大的吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"두목이랑 어울리는 것도 내 자유니까.","JPN":"ボスに付き合ってやるのも俺の自由だからな。","ENG":"I choose you of my own accord.","TWN":"反正和老大在一起也是我的自由。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};